#include <bits/stdc++.h>
using namespace std;

const int N=4e4+4,M=80;

int n,m,len,a[N],b[N],cnt[M][N],g[M][M],tmp[N];
map<int,int> id;

int Get(int x){
    return (x-1)/len+1;
}

int query(int l,int r){
    int p=Get(l),q=Get(r);
    if(p==q){
        int res=0,mx=0;
        for(int i=l;i<=r;i++){
            tmp[a[i]]++;
            if(tmp[a[i]]>mx || (tmp[a[i]]==mx && res>a[i]))
                res=a[i],mx=tmp[a[i]];
        }
        for(int i=l;i<=r;i++)
            tmp[a[i]]--;
        return res;
    }
    int res=g[p+1][q-1],mx=cnt[q-1][res]-cnt[p][res];
    int i=l;
    for(;Get(i)==p;i++){
        tmp[a[i]]++;
        int num=tmp[a[i]]+cnt[q-1][a[i]]-cnt[p][a[i]];
        if(num>mx || (num==mx && a[i]<res))
            res=a[i],mx=num;
    }
    i=r;
    for(;Get(i)==q;i--){
        tmp[a[i]]++;
        int num=tmp[a[i]]+cnt[q-1][a[i]]-cnt[p][a[i]];
        if(num>mx || (num==mx && a[i]<res))
            res=a[i],mx=num;
    }
    i=l;
    for(;Get(i)==p;i++)
        tmp[a[i]]--;
    i=r;
    for(;Get(i)==q;i--)
        tmp[a[i]]--;
    return res;
}

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++){
        scanf("%d",&a[i]);
        b[i]=a[i];
    }
    sort(b+1,b+n+1);
    int tot=unique(b+1,b+n+1)-b-1;
    for(int i=1;i<=tot;i++)
        id[b[i]]=i;
    for(int i=1;i<=n;i++)
        a[i]=id[a[i]];
    len=pow(n,1.0/3.0);
    len=n/len+(n%len>0);
    for(int i=1;i<=(n+len-1)/len;i++){
        for(int j=1;j<=n;j++)
            cnt[i][j]=cnt[i-1][j];
        for(int j=min(i*len,n);j>(i-1)*len;j--)
            cnt[i][a[j]]++;
    }
    for(int i=1;i<=(n+len-1)/len;i++)
        for(int j=i;j<=(n+len-1)/len;j++)
            for(int k=1;k<=n;k++)
                if(cnt[j][k]-cnt[i-1][k]>cnt[j][g[i][j]]-cnt[i-1][g[i][j]])
                    g[i][j]=k;
    int last=0;
    while(m--){
        int l,r;
        scanf("%d%d",&l,&r);
        l=(l+last-1)%n+1,r=(r+last-1)%n+1;
        if(l>r)
            swap(l,r);
        last=b[query(l,r)];
        printf("%d\n",last);
    }
    return 0;
}
